-- Ken's Hardened V2 Fix

local b64_0xlI11I1 = {}
local char_0xlI1ll1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlllIIl=1,#char_0xlI1ll1 do b64_0xlI11I1[char_0xlI1ll1:sub(i_0xlllIIl,i_0xlllIIl)] = i_0xlllIIl - 1 end

function b64_0xlI11I1.dec_0xllllII(d_0xllIllI)
    d_0xllIllI = string.gsub(d_0xllIllI, '[^'..char_0xlI1ll1..'=]', '')
    local r_0xlllIll = {}
    for i_0xlllIIl=1, #d_0xllIllI, 4 do
        local c_0xlIlI11 = b64_0xlI11I1[d_0xllIllI:sub(i_0xlllIIl,i_0xlllIIl)] or 0
        local c_0xI1Ill1 = b64_0xlI11I1[d_0xllIllI:sub(i_0xlllIIl+1,i_0xlllIIl+1)] or 0
        local c_0xIIl11l, c_0xllIIII = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xllIllI:sub(i_0xlllIIl+2,i_0xlllIIl+2)
        if ch3 == "=" then has3 = false else c_0xIIl11l = b64_0xlI11I1[ch3] or 0 end
        local ch4 = d_0xllIllI:sub(i_0xlllIIl+3,i_0xlllIIl+3)
        if ch4 == "=" then has4 = false else c_0xllIIII = b64_0xlI11I1[ch4] or 0 end
        local b_0xI1Illl = c_0xlIlI11 * (2^18) + c_0xI1Ill1 * (2^12) + c_0xIIl11l * (2^6) + c_0xllIIII
        local b_0xllll1I = math.floor(b_0xI1Illl / (2^16)) % (2^8)
        local b_0x1l11II = math.floor(b_0xI1Illl / (2^8)) % (2^8)
        local b_0xlIllIl = b_0xI1Illl % (2^8)
        table.insert(r_0xlllIll, string.char(b_0xllll1I))
        if has3 then table.insert(r_0xlllIll, string.char(b_0x1l11II)) end
        if has4 then table.insert(r_0xlllIll, string.char(b_0xlIllIl)) end
    end
    return table.concat(r_0xlllIll)
end


local function bxor_0xI1l1Il(a_0x1Il1ll,b_0xIlI11l)
    if bit32 then return bit32.bxor(a_0x1Il1ll,b_0xIlI11l) end
    local r_0xIl1I1I = 0
    for i_0xIl1III = 0, 7 do
        local x_0x1lll1I = a_0x1Il1ll % 2
        local y_0xlllI11 = b_0xIlI11l % 2
        if x_0x1lll1I ~= y_0xlllI11 then r_0xIl1I1I = r_0xIl1I1I + (2^i_0xIl1III) end
        a_0x1Il1ll = math.floor(a_0x1Il1ll / 2)
        b_0xIlI11l = math.floor(b_0xIlI11l / 2)
    end
    return r_0xIl1I1I
end


local function bxor_str_0xII1IIl(s_0xIll1ll, k_0xIl1l1I)
    local r_0xlI1IIl = {}
    for i_0xIl111I=1, #s_0xIll1ll do
        local b_0xl1IllI = string.byte(s_0xIll1ll, i_0xIl111I)
        local kb_0x1l1lIl = string.byte(k_0xIl1l1I, (i_0xIl111I-1) % #k_0xIl1l1I + 1)
        r_0xlI1IIl[i_0xIl111I] = string.char(bxor_0xI1l1Il(b_0xl1IllI, kb_0x1l1lIl))
    end
    return table.concat(r_0xlI1IIl)
end


local function getkeys_0xIllll1()
    local seed = b64_0xlI11I1.dec_0xllllII("M3FrdGt3eFU=")
    local k1_enc = b64_0xlI11I1.dec_0xllllII("eT9aRwYVCy0=")
    local k2_enc = b64_0xlI11I1.dec_0xllllII("ajAPGSodGgI=")
    return bxor_str_0xII1IIl(k1_enc, seed), bxor_str_0xII1IIl(k2_enc, seed)
end


local function cff_0xlIIlI1(a_0x11I1ll)
    local st_0xllIIIl = 0
    local res_0xllIllI = a_0x11I1ll
    while true do
        if st_0xllIIIl == 0 then
            res_0xllIllI = res_0xllIllI + 1
            st_0xllIIIl = 1
        elseif st_0xllIIIl == 1 then
            res_0xllIllI = res_0xllIllI * 2
            st_0xllIIIl = 2
        elseif st_0xllIIIl == 2 then
            res_0xllIllI = res_0xllIllI - 3
            st_0xllIIIl = 3
        else
            break
        end
    end
    return res_0xllIllI
end


local function chain_0x1lII1I(x) return x*2 end
local function chain_0xI1lIll(x) return chain_0x1lII1I(x)+1 end


local d_0xIIllIl = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIIIll = 1
local stk_0xllIIl1 = {}
stk_0xllIIl1._jmp = nil


local disp_0xIIlIll = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIllll1()

local state_0xlI1lll = 0
while true do
    if state_0xlI1lll == 0 then  -- FETCH
        if pc_0xlIIIll > #d_0xIIllIl then break end
        local inst = d_0xIIllIl[pc_0xlIIIll]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlI11I1.dec_0xllllII(val)
            d = bxor_str_0xII1IIl(d, k2)
            val = bxor_str_0xII1IIl(d, k1)
        end
        stk_0xllIIl1._jmp = nil
        pc_0xlIIIll = pc_0xlIIIll + 1
        cur_op_0x11IIll = opcode
        cur_val_0xIIllII = val
        state_0xlI1lll = 1

