        local handler = disp_0xIIlIll[cur_op_0x11IIll]
        if handler then
            handler(stk_0xllIIl1, cur_val_0xIIllII)
        end
        if stk_0xllIIl1._jmp then
            pc_0xlIIIll = pc_0xlIIIll + stk_0xllIIl1._jmp
        end
        state_0xlI1lll = 0
